// v2 response keeps both during deprecation period:
{ "username": "alice", "displayName": "alice", "email": "..." }
// with header: Deprecation: username; sunset=2025-06-01

// New required param breaks existing clients
app.post('/search', (req, res) => {
  const { query, region } = req.body; // region now required
  if (!region) return res.status(400).json({ error: 'region required' });
});

app.post('/search', (req, res) => {
  const { query, region = 'us-east-1' } = req.body; // default preserves behavior
});

// Only a comment, no machine-readable signal
// @deprecated - use /v2/users instead
app.get('/v1/users', handler);

app.get('/v1/users', (req, res) => {
  res.set('Deprecation', 'true');
  res.set('Sunset', 'Sat, 01 Jun 2025 00:00:00 GMT');
  res.set('Link', '</v2/users>; rel="successor-version"');
  handler(req, res);
});

app.get('/v1/legacy', (req, res) => {
  metrics.increment('deprecated.v1_legacy.requests', {
    client: req.headers['x-client-id']
  });
  handler(req, res);
});

class ApiClient {
  search(query: string) { /* still points to v1 */ }
}

class ApiClient {
  /** @deprecated Use searchV2() instead. Will be removed 2025-06-01. */
  search(query: string) { /* v1 */ }
  searchV2(query: string, options: SearchOptions) { /* v2 */ }
}

// Transformation duplicated in each handler
app.get('/v1/users/:id', async (req, res) => {
  const user = await userService.find(req.params.id);
  res.json({ username: user.name, mail: user.email });
});
app.get('/v2/users/:id', async (req, res) => {
  const user = await userService.find(req.params.id);
  res.json({ displayName: user.name, email: user.email });
});

const mappers = {
  v1: (user) => ({ username: user.name, mail: user.email }),
  v2: (user) => ({ displayName: user.name, email: user.email }),
};
app.get('/:version/users/:id', async (req, res) => {
  const user = await userService.find(req.params.id);
  res.json(mappers[req.params.version](user));
});

// Exhaustive match with no fallback
switch (order.status) {
  case 'pending': handle(); break;
  case 'shipped': handle(); break;
  // new 'on_hold' status causes error
}

switch (order.status) {
  case 'pending': handle(); break;
  case 'shipped': handle(); break;
  default: handleUnknown(order.status); break;
